import{o as s,c as n,a}from"./app.a612cc0f.js";const p='{"title":"Css 样式","description":"","frontmatter":{},"headers":[{"level":2,"title":"css 替换 important","slug":"css-替换-important"},{"level":2,"title":"flex 兼容","slug":"flex-兼容"}],"relativePath":"guide/h5/css.md","lastUpdated":1622976166173}',e={},t=[a('<h1 id="css-样式"><a class="header-anchor" href="#css-样式" aria-hidden="true">#</a> Css 样式</h1><h2 id="css-替换-important"><a class="header-anchor" href="#css-替换-important" aria-hidden="true">#</a> css 替换 important</h2><p>项目中，需要覆盖原来的 css 样式，可以使用<code>!important</code></p><div class="language-less line-numbers-mode"><pre><code><span class="token selector">.sidebar</span> <span class="token punctuation">{</span>\n  <span class="token comment">// 原来定义值</span>\n  <span class="token property">width</span><span class="token punctuation">:</span> 20rem<span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n\n<span class="token selector">.sidebar</span> <span class="token punctuation">{</span>\n  <span class="token comment">// 以新值替换</span>\n  <span class="token property">width</span><span class="token punctuation">:</span> 16rem <span class="token important">!important</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers-wrapper"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h2 id="flex-兼容"><a class="header-anchor" href="#flex-兼容" aria-hidden="true">#</a> flex 兼容</h2><p>flex 布局分为旧版本 dispaly: box;，过渡版本 dispaly: flex box;，以及现在的标准版本 display: flex;。 所以只是写新版本的语法形式，是肯定存在兼容性问题的。</p><ul><li><p>支持版本</p><ul><li>Android 2.3 开始就支持旧版本 display:-webkit-box; 4.4 开始支持标准版本 display: flex;</li><li>IOS 6.1 开始支持旧版本 display:-webkit-box; 7.1 开始支持标准版本 display: flex;</li><li>PC ie10 开始支持，但是 IE10 的是-ms 形式的。</li></ul></li><li><p>盒子的兼容性写法</p></li></ul><p>写法的顺序一定要按最新到最旧的顺序，否则不起作用</p><div class="language-less line-numbers-mode"><pre><code><span class="token comment">// 部署兼容</span>\n<span class="token selector">.flex()</span> <span class="token punctuation">{</span>\n  <span class="token property">display</span><span class="token punctuation">:</span> <span class="token operator">-</span>webkit<span class="token operator">-</span>flex<span class="token punctuation">;</span> <span class="token comment">// 新版本语法: Chrome 21+</span>\n  <span class="token property">display</span><span class="token punctuation">:</span> flex<span class="token punctuation">;</span> <span class="token comment">//  新版本语法: Opera 12.1, Firefox 22+</span>\n  <span class="token property">display</span><span class="token punctuation">:</span> <span class="token operator">-</span>webkit<span class="token operator">-</span>box<span class="token punctuation">;</span> <span class="token comment">// 老版本语法: Safari, iOS, Android browser, older WebKit browsers.</span>\n  <span class="token property">display</span><span class="token punctuation">:</span> <span class="token operator">-</span>moz<span class="token operator">-</span>box<span class="token punctuation">;</span> <span class="token comment">//  老版本语法: Firefox (buggy)</span>\n  <span class="token property">display</span><span class="token punctuation">:</span> <span class="token operator">-</span>ms<span class="token operator">-</span>flexbox<span class="token punctuation">;</span> <span class="token comment">//  混合版本语法: IE 10</span>\n<span class="token punctuation">}</span>\n\n<span class="token selector">.box</span> <span class="token punctuation">{</span>\n  <span class="token mixin-usage function">.flex</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers-wrapper"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><ul><li>子元素的兼容性写法</li></ul><div class="language-css line-numbers-mode"><pre><code><span class="token selector">.flex1</span> <span class="token punctuation">{</span>\n    <span class="token property">-webkit-flex</span><span class="token punctuation">:</span> 1<span class="token punctuation">;</span>        <span class="token comment">/* Chrome */</span>\n    <span class="token property">-ms-flex</span><span class="token punctuation">:</span> 1             <span class="token comment">/* IE 10 */</span>\n    <span class="token property">flex</span><span class="token punctuation">:</span> 1<span class="token punctuation">;</span>                <span class="token comment">/* NEW, Spec - Opera 12.1, Firefox 20+ */</span>\n    <span class="token property">-webkit-box-flex</span><span class="token punctuation">:</span> 1     <span class="token comment">/* OLD - iOS 6-, Safari 3.1-6 */</span>\n    <span class="token property">-moz-box-flex</span><span class="token punctuation">:</span> 1<span class="token punctuation">;</span>       <span class="token comment">/* OLD - Firefox 19- */</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers-wrapper"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div>',11)];e.render=function(a,p,e,l,o,c){return s(),n("div",null,t)};export{p as __pageData,e as default};
